import React from 'react';
import ParamHeader from './ParamHeader';

function Brightness({ brightness, onBrightnessChange, paramIcons, onIconClick, buttonRefs }) {
  return (
    <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
      <div className="flex items-center justify-between mb-2">
        <ParamHeader
          paramKey="brightness"
          label="亮度"
          iconColor="text-yellow-500"
          onIconClick={onIconClick}
          buttonRef={(el) => buttonRefs.current.brightness = el}
        />
        <span className="text-sm font-bold text-pink-500">{brightness}%</span>
      </div>
      <input
        type="range"
        min="0"
        max="100"
        value={brightness}
        onChange={(e) => onBrightnessChange(parseInt(e.target.value))}
        className="w-full h-2 bg-gradient-to-r from-yellow-200 to-yellow-400 rounded-full appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-5 [&::-webkit-slider-thumb]:h-5 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:shadow-lg [&::-webkit-slider-thumb]:border-2 [&::-webkit-slider-thumb]:border-yellow-400"
      />
    </div>
  );
}

export default Brightness;
